/* adc_pipeline.h — 多层滤波架构的接口定义 */
#ifndef ADC_PIPELINE_H
#define ADC_PIPELINE_H

#include "stm32f4xx_hal.h"
#include <stdint.h>

/* 配置参数 */
#define ADC_OVERSAMPLE_COUNT    16     /* 硬件过采样次数 */
#define ADC_IIR_ALPHA_LOG2      6      /* IIR 系数: alpha = 1/2^6 = 1/64 */
#define ADC_MOVING_AVG_WINDOW   32     /* 移动平均窗口 */

/* 滤波状态 */
typedef struct {
    uint32_t iir_accumulator;       /* IIR 滤波器状态（32位定点）
                                       Q24.8 格式，8位小数 */
    int32_t avg_buffer[ADC_MOVING_AVG_WINDOW];
    uint8_t avg_idx;
} adc_filter_state_t;

/* 读取通道并返回滤波后的值（16位精度） */
uint16_t adc_read_filtered(ADC_HandleTypeDef* hadc, uint8_t channel,
                           adc_filter_state_t* state);

/* 初始化过采样器 */
void adc_oversampler_init(ADC_HandleTypeDef* hadc, uint8_t oversample_ratio);

#endif

/* 伪代码架构图：
 * 
 * 信号 → [RC低通, fc=4.8kHz] → [ADC转换, 12位] → [硬件过采样×16] 
 *      → [软件IIR α=1/64] → [软件移动平均×32] → 应用层 uint16_t
 * 
 * 每一层之间通过接口隔离，应用层只看到 uint16_t 结果 */

#include "adc_pipeline.h"
#include <string.h>

/* 硬件过采样器初始化
 * oversample_ratio: 2, 4, 8, 16（必须在 ADC 关闭时配置）*/
void adc_oversampler_init(ADC_HandleTypeDef* hadc, uint8_t oversample_ratio) {
    /* 1. 确保 ADC 已关闭 */
    __HAL_ADC_DISABLE(hadc);

    /* 2. 配置过采样：右移量 = log2(oversample_ratio)
     * 例如 16x → 右移 4 位
     */
    uint8_t shift = 0;
    uint8_t ratio = oversample_ratio;
    while (ratio > 1) { ratio >>= 1; shift++; }

    /* 3. 设置 ADC_CR2 寄存器的 OVERSCAN 和 OVERS 位
     * OVRSC[1:0] = 01 → 过采样累加器右移
     * OVERSC[4:0] = shift → 右移位数
     * ENHOC = 1 → 使能过采样器 */
    CLEAR_BIT(hadc->Instance->CR2, ADC_CR2_OVRS | ADC_CR2_OVRSC);
    SET_BIT(hadc->Instance->CR2, ADC_CR2_OVSE);  /* 使能过采样 */
    hadc->Instance->CR2 |= (shift << 3) | (1 << 2);  /* OVERSC | OVRSC=01 */
}

/* 读取通道并返回滤波后的值 */
uint16_t adc_read_filtered(ADC_HandleTypeDef* hadc, uint8_t channel,
                           adc_filter_state_t* state) {
    /* Step 1: 切换通道并启动单次转换 */
    ADC_ChannelConfTypeDef sConfig = {0};
    sConfig.Channel = channel;           /* 例如 ADC_CHANNEL_0 */
    sConfig.Rank = 1;
    sConfig.SamplingTime = ADC_SAMPLETIME_144CYCLES;  /* 4μs @ 36MHz */
    HAL_ADC_ConfigChannel(hadc, &sConfig);

    /* Step 2: 启动转换，等待完成 */
    HAL_ADC_Start(hadc);                 /* 单次模式，硬件过采样自动启动 */
    HAL_ADC_PollForConversion(hadc, 10); /* 超时 10ms */

    /* Step 3: 读取过采样后的值（DR 寄存器，已右移 4 位）*/
    uint16_t raw = (uint16_t)HAL_ADC_GetValue(hadc);  /* 读 ADC_DR */

    /* Step 4: 软件 IIR 低通滤波（Q24.8 定点，α = 1/64）*/
    uint32_t sample_q8 = (uint32_t)raw << 8;       /* 扩展到 Q24.8 */
    uint32_t alpha = 1UL << ADC_IIR_ALPHA_LOG2;     /* alpha = 64 */
    uint32_t filtered = (state->iir_accumulator \
                         + sample_q8) / alpha;       /* 一阶 IIR */
    state->iir_accumulator = filtered;

    /* Step 5: 移动平均滤波（环形缓冲区）*/
    state->avg_buffer[state->avg_idx] = (int32_t)filtered;
    state->avg_idx = (state->avg_idx + 1) & (ADC_MOVING_AVG_WINDOW - 1);

    /* 计算平均值：线性扫描 */
    int32_t sum = 0;
    for (int i = 0; i < ADC_MOVING_AVG_WINDOW; i++) {
        sum += state->avg_buffer[i];
    }
    uint16_t result = (uint16_t)(sum / ADC_MOVING_AVG_WINDOW);

    return result;
}

/* 陷阱2演示：通道切换后的建立时间检查 */
void ADC_MultiChannel_Read(ADC_HandleTypeDef* hadc, uint8_t* channels,
                           uint8_t count, uint16_t* results) {
    /* 错误做法：所有通道用 3 周期采样时间 */
    /* sConfig.SamplingTime = ADC_SAMPLETIME_3CYCLES; */
    /* 高阻抗源（Rsource > 50kΩ）时，3 周期不够建立到 12 位精度 */

    /* 正确做法：根据源阻抗选择采样时间 */
    for (int i = 0; i < count; i++) {
        ADC_ChannelConfTypeDef sConfig = {0};
        sConfig.Channel = channels[i];
        sConfig.Rank = 1;

        /* 根据源阻抗选择采样时间 */
        /* Rsource < 10kΩ → 144 周期 */
        /* Rsource 10k-50kΩ → 239 周期 */
        /* Rsource > 50kΩ → 480 周期（最低阻抗要求）*/
        sConfig.SamplingTime = ADC_SAMPLETIME_480CYCLES;

        HAL_ADC_ConfigChannel(hadc, &sConfig);
        HAL_ADC_Start(hadc);
        HAL_ADC_PollForConversion(hadc, 10);
        results[i] = (uint16_t)HAL_ADC_GetValue(hadc);
    }
}

/* 陷阱4演示：输入引脚 PI 型滤波 */
/* 硬件电路：
 * 信号 → [100Ω] → ADC_PIN → [100pF] → GND
 * 
 * 截止频率：f_c = 1/(2π×100×100×10^-12) ≈ 15.9MHz
 * 对 PWM 20kHz 的衰减：20log(15.9MHz / 20kHz) ≈ 68dB
 * 对信号 1kHz 的衰减：20log(15.9MHz / 1kHz) ≈ 104dB → 无影响
 */

/* ========== 改进前：轮询单次采样 ========== */
/* 问题：阻塞、抖动大、无法过采样、CPU 被占用 */
void Read_Currents_Polling(ADC_HandleTypeDef* hadc, float* i_u, float* i_v, float* i_w) {
    /* 采样 U 相 */
    ADC_ChannelConfTypeDef cfg = {0};
    cfg.Channel = ADC_CHANNEL_1;  /* U 相 */
    cfg.Rank = 1;
    cfg.SamplingTime = ADC_SAMPLETIME_84CYCLES;
    HAL_ADC_ConfigChannel(hadc, &cfg);
    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, 10);  /* 阻塞等待 */
    *i_u = HAL_ADC_GetValue(hadc) * 3.3f / 4096.0f * current_scale;

    /* 采样 V 相 */
    cfg.Channel = ADC_CHANNEL_2;  /* V 相 */
    HAL_ADC_ConfigChannel(hadc, &cfg);
    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, 10);  /* 再次阻塞 */
    *i_v = HAL_ADC_GetValue(hadc) * 3.3f / 4096.0f * current_scale;

    /* 采样 W 相 */
    cfg.Channel = ADC_CHANNEL_3;  /* W 相 */
    HAL_ADC_ConfigChannel(hadc, &cfg);
    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, 10);  /* 第三次阻塞 */
    *i_w = HAL_ADC_GetValue(hadc) * 3.3f / 4096.0f * current_scale;

    /* 问题1：三次阻塞总共占用了 ~12μs，期间 CPU 什么都没做
     * 问题2：每次采样时间取决于前一次，抖动 > 500ns
     * 问题3：无法过采样（太慢了）
     * 问题4：FOC 需要在 100kHz 开关频率下每 10μs 采样一次，
     *         单次采样已经占了 12μs，无法完成 */
}

/* ========== 改进后：DMA 双缓冲 + 定时触发 ========== */
#define DMA_BUF_SAMPLES     64
#define DMA_BUF_COUNT       2

static uint16_t adc_dma_buf[DMA_BUF_COUNT][DMA_BUF_SAMPLES];
static volatile uint8_t dma_buf_ready = 0;   /* 哪个缓冲区已就绪 */
static volatile uint8_t dma_half_ready = 0;  /* Half-Complete 标记 */

void ADC_DMA_Init(ADC_HandleTypeDef* hadc, DMA_HandleTypeDef* hdma) {
    /* 1. 配置 DMA：循环模式，HALF_WORD 宽度，外设地址固定 */
    hdma->Instance = DMA2_Stream0;
    hdma->Init.Channel = DMA_CHANNEL_0;
    hdma->Init.Direction = DMA_PERIPH_TO_MEMORY;
    hdma->Init.PeriphInc = DMA_PINC_DISABLE;     /* ADC_DR 地址固定 */
    hdma->Init.MemInc = DMA_MINC_ENABLE;         /* 缓冲区地址递增 */
    hdma->Init.PeriphDataAlignment = DMA_PDATAALIGN_HALFWORD;
    hdma->Init.MemDataAlignment = DMA_MDATAALIGN_HALFWORD;
    hdma->Init.Mode = DMA_CIRCULAR;              /* 循环模式 */
    hdma->Init.Priority = DMA_PRIORITY_HIGH;
    HAL_DMA_Init(hdma);

    /* 2. 配置 ADC：定时器触发，连续模式，DMA 循环 */
    hadc->Init.ContinuousConvMode = ENABLE;
    hadc->Init.DMAContinuousRequests = ENABLE;
    hadc->Init.ExternalTrigConv = ADC_EXTERNALTRIGCONV_T2_TRGO;  /* TIM2 TRGO */
    hadc->Init.ScanConvMode = ENABLE;  /* 多通道 */

    /* 3. 启动 DMA */
    HAL_ADC_Start_DMA(hadc, (uint32_t*)adc_dma_buf, 
                      DMA_BUF_COUNT * DMA_BUF_SAMPLES);
}

/* DMA 传输完成回调 */
void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef* hadc) {
    /* DMA_BUF_1 填充完成（64 个样本）*/
    dma_buf_ready = 1;
    /* 在中断中做 IIR 滤波 + 过采样平均 */
    process_dma_buffer(adc_dma_buf[1], DMA_BUF_SAMPLES);
}

void HAL_ADC_ConvHalfCpltCallback(ADC_HandleTypeDef* hadc) {
    /* DMA_BUF_0 填充完成 */
    dma_half_ready = 1;
    process_dma_buffer(adc_dma_buf[0], DMA_BUF_SAMPLES);
}

/* 应用层：非阻塞读取 */
void Read_Currents_DMA(float* i_u, float* i_v, float* i_w) {
    if (!dma_buf_ready && !dma_half_ready) return;  /* 无新数据 */

    /* 直接读滤波后的结果（由 DMA 回调已经计算好）*/
    *i_u = g_filtered_u_current;
    *i_v = g_filtered_v_current;
    *i_w = g_filtered_w_current;

    /* 清除标记 */
    dma_buf_ready = 0;
    dma_half_ready = 0;
}

/* 代价分析：
 * + 内存：2 × 64 × 2 = 256 字节（可接受）
 * + 中断延迟：~64 × 4μs = 256μs 流水线延迟
 * - 复杂度：需要管理双缓冲和同步
 * - 但 FOC 可以在 256μs 延迟内正常工作，且 CPU 完全释放 */
